import axios from 'axios';
import React, { useEffect, useState } from 'react';

export const Rasp = () => {
  const [rasps, setRasps] = useState([]);
  const [filteredRasps, setFilteredRasps] = useState([]);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    axios.get("http://localhost:5555/rasps")
      .then(response => setRasps(response.data))
      .catch(err => console.log(err));
  }, []);

  useEffect(() => {
    // Filtreleme işlemi burada gerçekleşecek
    const filteredData = rasps.filter(item => {
      // Filtreleme kriterlerini buraya ekleyebilirsin
      return item.predmet.predmet.toLowerCase().includes(filter.toLowerCase());
    });

    // Aynı öğretmenin aynı gün ve saatte iki defa yazıldığını kontrol et
    const duplicateTeachers = findDuplicateTeachers(filteredData);
    setFilteredRasps(duplicateTeachers);
  }, [filter, rasps]);

  // Aynı öğretmenin aynı gün ve saatte iki defa yazıldığını kontrol eden fonksiyon
  const findDuplicateTeachers = (data) => {
    const teacherMap = new Map();
    const duplicateTeachers = [];

    data.forEach(item => {
      const key = `${item.teacher.teacher}_${item.day.day}_${item.time.time}`;
      if (teacherMap.has(key)) {
        duplicateTeachers.push(item);
      } else {
        teacherMap.set(key, true);
      }
    });

    return duplicateTeachers;
  };

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
      <strong className="text-gray-700 font-medium">Расписания</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        {/* Filtreleme arayüzü */}
        <input
          type="text"
          placeholder="Filtrele"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
        />
        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Время</th>
              <th>День</th>
              <th>Предмет</th>
              <th>Группа</th>
              <th>Преподаватель</th>
              <th>Курс</th>
              <th>Кабинет</th>
            </tr>
          </thead>
          <tbody>
            {filteredRasps.map(item => (
              <tr key={item._id} style={{ color: 'red' }}>
                <td>{item.time.time}</td>
                <td>{item.day.day}</td>
                <td>{item.predmet.predmet}</td>
                <td>{item.group.group_number}</td>
                <td>{item.teacher.teacher}</td>
                <td>{item.group.kurs}</td>
                <td>{item.room}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};
